import org.apache.spark.sql.SparkSession
import org.apache.spark.sql.DataFrame
import org.apache.spark.sql.functions._
import org.apache.spark.sql.types._
import scala.util.{Try, Success, Failure}

case class QueryRequest(sql: String)
case class QueryResponse(data: List[Map[String, Any]], schema: String)
case class ErrorResponse(message: String, code: Int)

object AnalyticsEngine {
  private val spark: SparkSession = SparkSession.builder()
    .appName("AnalyticsEngine")
    .config("spark.sql.adaptive.enabled", "true")
    .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
    .getOrCreate()

  def executeQuery(sql: String): Try[DataFrame] = {
    Try(spark.sql(sql))
  }

  def processQuery(sql: String): Try[QueryResponse] = {
    executeQuery(sql) match {
      case Success(df) =>
        val data = df.collect().map(row => {
          val map = scala.collection.mutable.Map[String, Any]()
          row.schema.fields.foreach { field =>
            map(field.name) = row.get(field.name)
          }
          map.toMap
        }).toList

        val schema = df.schema.fields.map(field => 
          s"${field.name}:${field.dataType.typeName}"
        ).mkString(",")

        Success(QueryResponse(data, schema))
      case Failure(exception) =>
        Failure(exception)
    }
  }

  def close(): Unit = {
    spark.stop()
  }
}

object QueryProcessor {
  def processRequest(queryRequest: QueryRequest): Either[ErrorResponse, QueryResponse] = {
    AnalyticsEngine.processQuery(queryRequest.sql) match {
      case Success(response) => Right(response)
      case Failure(exception) => 
        Left(ErrorResponse(exception.getMessage, 500))
    }
  }
}

object AnalyticsServer {
  def main(args: Array[String]): Unit = {
    val engine = AnalyticsEngine
    
    // Example usage
    val testQueries = List(
      "SELECT * FROM users LIMIT 10",
      "SELECT COUNT(*) as total FROM transactions",
      "SELECT product_category, SUM(amount) as total_sales FROM sales GROUP BY product_category"
    )

    testQueries.foreach { query =>
      QueryProcessor.processRequest(QueryRequest(query)) match {
        case Right(response) => 
          println(s"Query: $query")
          println(s"Schema: ${response.schema}")
          println(s"Data: ${response.data}")
        case Left(error) => 
          println(s"Error executing query: ${error.message}")
      }
    }
    
    engine.close()
  }
}